import machine
import time
from umqtt.simple import MQTTClient

# Initialize I2C and get temperature from DS18B20 sensor
i2c = machine.I2C(scl=machine.Pin(22), sda=machine.Pin(21))
ds18b20_address = 0x48
ds18b20 = machine.SPI(1, baudrate=100000)
temperature = ds18b20.readbyte(ds18b20_address)

# MQTT settings
broker_ip = '192.168.4.1'
client_id = 'ESP32_Sensor_Node'

# Create an MQTT client instance
client = MQTTClient(client_id, broker_ip)

# Connect to the MQTT broker
try:
    client.connect()
except Exception as e:
    print('Connection failed: ', str(e))
    while True:
        pass

while True:
    temperature = ds18b20.readbyte(ds18b20_address)
    topic = b'sensors/temp'
    msg = b'%.2f' % (temperature / 16)
    
    client.publish(topic, msg)
    time.sleep(10)

# Cleanup
client.disconnect()